import { NextRequest, NextResponse } from 'next/server';
import { db } from '@/lib/db';
import { analysisTasks, analysisArticles, insightReports } from '@/lib/db/schema';
import { eq } from 'drizzle-orm';

export async function POST(request: NextRequest) {
  const body = await request.json();
  const { taskId, keyword } = body;
  const database = db();

  try {
    await database.update(analysisTasks)
      .set({ status: 'processing', startedAt: new Date() })
      .where(eq(analysisTasks.id, taskId));

    const mockArticles = await fetchMockArticles(keyword);
    
    await database.update(analysisTasks)
      .set({ totalArticles: mockArticles.length })
      .where(eq(analysisTasks.id, taskId));

    const analyzedArticles: Array<{
      title: string;
      author: string;
      url: string;
      readCount: number;
      likeCount: number;
      commentCount: number;
      shareCount: number;
      engagementRate: number;
      summary: string;
      keywords: string[];
    }> = [];

    for (let i = 0; i < mockArticles.length; i++) {
      const article = mockArticles[i];
      
      const summary = await analyzeArticleWithAI(article.title, article.content || '');
      
      const engagementRate = article.readCount > 0 
        ? ((article.likeCount + article.commentCount + article.shareCount) / article.readCount) * 100 
        : 0;

      const analyzedArticle = {
        taskId,
        title: article.title,
        author: article.author,
        url: article.url,
        summary: summary.summary,
        readCount: article.readCount,
        likeCount: article.likeCount,
        commentCount: article.commentCount,
        shareCount: article.shareCount,
        engagementRate,
        publishDate: article.publishDate,
        keywords: summary.keywords,
        analyzedAt: new Date(),
      };

      await database.insert(analysisArticles).values(analyzedArticle);
      
      analyzedArticles.push({
        title: article.title,
        author: article.author,
        url: article.url,
        readCount: article.readCount,
        likeCount: article.likeCount,
        commentCount: article.commentCount,
        shareCount: article.shareCount,
        engagementRate,
        summary: summary.summary,
        keywords: summary.keywords,
      });

      await database.update(analysisTasks)
        .set({ analyzedArticles: i + 1 })
        .where(eq(analysisTasks.id, taskId));
    }

    const report = await generateInsightReport(analyzedArticles, keyword);

    await database.insert(insightReports).values({
      taskId,
      topLikesArticles: report.topLikesArticles,
      topEngagementArticles: report.topEngagementArticles,
      wordCloud: report.wordCloud,
      insights: report.insights,
      topicSuggestions: report.topicSuggestions,
    });

    await database.update(analysisTasks)
      .set({ status: 'completed', completedAt: new Date() })
      .where(eq(analysisTasks.id, taskId));

    return NextResponse.json({ success: true });
  } catch (error) {
    console.error('Analysis error:', error);
    
    await database.update(analysisTasks)
      .set({ 
        status: 'failed', 
        errorMessage: error instanceof Error ? error.message : '分析失败',
        completedAt: new Date() 
      })
      .where(eq(analysisTasks.id, taskId));

    return NextResponse.json({ error: '分析失败' }, { status: 500 });
  }
}

async function fetchMockArticles(keyword: string): Promise<Array<{
  title: string;
  author: string;
  url: string;
  readCount: number;
  likeCount: number;
  commentCount: number;
  shareCount: number;
  publishDate: string;
  content: string;
}>> {
  const articles = [];
  const count = 20 + Math.floor(Math.random() * 10);
  
  const titleTemplates = [
    `${keyword}实战指南：从入门到精通的完整路线`,
    `为什么${keyword}正在改变行业格局？深度解析`,
    `${keyword}核心技巧揭秘，新手也能快速上手`,
    `我用${keyword}实现了10倍效率提升，方法分享`,
    `${keyword}避坑指南：这些错误千万别犯`,
    `深度复盘：${keyword}项目从0到1的全过程`,
    `${keyword}与AI结合，开启新机遇`,
    `从零开始学${keyword}，这份教程价值百万`,
    `${keyword}最新趋势解读，把握未来方向`,
    `实战案例：${keyword}如何解决实际问题`,
  ];

  for (let i = 0; i < count; i++) {
    const template = titleTemplates[i % titleTemplates.length];
    articles.push({
      title: template,
      author: `作者${String.fromCharCode(65 + (i % 26))}`,
      url: `https://mp.weixin.qq.com/article-${i + 1}`,
      readCount: Math.floor(Math.random() * 50000) + 1000,
      likeCount: Math.floor(Math.random() * 2000) + 50,
      commentCount: Math.floor(Math.random() * 500) + 10,
      shareCount: Math.floor(Math.random() * 1000) + 20,
      publishDate: new Date(Date.now() - Math.random() * 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0],
      content: `这是关于${keyword}的第${i + 1}篇文章的正文内容...`,
    });
  }

  return articles;
}

async function analyzeArticleWithAI(title: string, content: string): Promise<{ summary: string; keywords: string[] }> {
  const keywords = extractKeywords(title + ' ' + content);
  
  return {
    summary: `文章《${title}》主要讨论了相关话题的核心要点和实践方法。`,
    keywords,
  };
}

